VALUES ('DII', 'D2_00007', 'Contábil', 'E/DF/M', 'Informação de despesas orçamentárias de custeio no Anexo I-D da DCA', 'DCA', 'ANEXO I - D', 'Verifica se foram informadas, no Anexo I-D da DCA, as despesas orçamentárias de outros grupos de natureza da despesa relacionados a custeio diferente de "Pessoal e Encargos Sociais" e "Juros e Encargos da Dívida".', FALSE);
