VALUES ('DII', 'D2_00008', 'Contábil', 'E/DF/M', 'Informação das despesa orçamentárias por função no Anexo I-E da DCA', 'DCA', 'ANEXO I - E', 'Verifica se foram informadas, no Anexo I-E da DCA, as despesas orçamentárias classificadas por função do gasto púbblico.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00010', 'Contábil', 'E/DF/M', 'Informação das receitas de transferências intergovernamentais no Anexo I-C da DCA', 'DCA', 'ANEXO I - C', 'Verifica se foram informadas, no Anexo I-C da DCA, as receitas orçamentárias de transferências de outros entes/entidades.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00011', 'Contábil', 'E/DF/M', 'Informação de receitas orçamentárias tributárias no Anexo I-C da DCA', 'DCA', 'ANEXO I - C', 'Verifica se foram informadas, no Anexo I-C da DCA, as receitas orçamentárias tributárias.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00012', 'Contábil', 'E/DF/M', 'Avalia a existência de receitas orçamentárias menores que suas deduções no Anexo I-C da DCA', 'DCA', 'ANEXO I - C', 'Verifica, no Anexo I-C da DCA, se o valor de deduções de receitas é superior às receitas brutas para cada uma das linhas. As naturezas de receitas começadas por 132 não são analisadas.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00013', 'Contábil', 'E/DF/M', 'Avalia a existência de ajustes para perdas maiores que os ativos originais no Anexo I-AB da DCA para "Créditos a curto e longo prazos"', 'DCA', 'ANEXO I - AB', 'Verifica a relação entre o ajuste para perdas dos "Créditos a curto e longo prazo" e suas contas principais no Anexo I-AB da DCA. O valor dos ajustes não pode ser superior aos valores das contas originais.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00014', 'Contábil', 'E/DF/M', 'Avalia a existência de ajustes para perdas maiores que os ativos originais no Anexo I-AB da DCA para "Demais créditos e valores a curto e longo prazo"', 'DCA', 'ANEXO I - AB', 'Verifica a relação entre o ajuste para perdas dos "Demais créditos e valores a curto e longo prazo" e suas contas principais no Anexo I-AB da DCA. O valor dos ajustes não pode ser superior aos valores das contas originais.', FALSE);
