VALUES ('DII', 'D2_00016', 'Contábil', 'E/DF/M', 'Informação de Depreciação acumulada de bens móveis no Anexo I-AB da DCA', 'DCA', 'ANEXO I - AB', 'Verifica se foi informado saldo patrimonial de depreciação acumulada de bens móveis no Anexo I-AB da DCA.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
