INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00018', 'Contábil', 'E/DF/M', 'Avalia se o valor dos bens móveis é maior que sua depreciação acumulada no Anexo I-AB da DCA', 'DCA', 'ANEXO I - AB', 'Verifica se os valores de depreciação de bens móveis é inferior ao valor  total de bens móveis no Anexo I-AB da DCA.', FALSE);
