VALUES ('DII', 'D2_00066', 'Contábil', 'E/DF/M', 'Avalia se o valor dos ativos intangíveis é maior que sua amortização acumulada no Anexo I-AB da DCA', 'DCA', 'DCA - Anexo I-AB', 'Verifica, na DCA, se o valor de amortização acumulada é inferior ao valor do ativo intangível. A avaliação é feita por tipo de ativo intangível.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
