INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00072', 'Contábil', 'E/DF/M', 'Avalia se o valor de despesas exceto-intra nas funções diferentes de 09, 10 e 12 é igual entre a MSC de encerramento e o Anexo I-E da DCA', 'MSC DCA', 'DCA - Anexo I-E/ MSC de encerramento', 'Compara, entre DCA X  MSC de Encerramento, as Despesas Exceto Intraorçamentárias nas demais funções (Excetuando-se as funções de Saúde, Educação e Previdência Social). Na MSC de encerramento, utliza-se o saldo inicial (beginning_balance) para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 62213 com modalidade de aplicação diferente de 91 e classificação funcional diferente de 09, 10 e 12.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
