INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DII', 'D2_00074', 'Contábil', 'E/DF/M', 'Avalia a igualdade entre os saldos finais de RPP pagos e RPNP pagos na MSC de Encerramento e no Anexo I-F da DCA', 'MSC DCA', 'DCA - Anexo I-F/ MSC de encerramento', 'Compara o saldo final de RPPP e RPNPP executados no exercício entre DCA X MSC de Encerramento. A verificação avalia separadamente os valores de RPP e de RPNP. Na MSC de encerramento, utliza-se o saldo inicial (beginning_balance) para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 6314 (RPNPP) e 6322 (RPPP).', FALSE);
