VALUES ('DIV', 'D4_00019', 'Contábil x Fiscal', 'E/DF/M', 'Igualdade do valor das despesas de capital entre o Anexo I-D da DCA e o Anexo 09 do RREO 6ºB.', 'DCA RREO', 'DCA - ANEXO I - D RREO - ANEXO 9', 'Verifica se o valor bruto das despesas de capital no Anexo I-D da DCA está igual ao Anexo 09 do RREO 6ºB.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00020', 'Contábil x Fiscal', 'E/DF/M', 'Igualdade nas receitas arrecadadas na MSC de dezembro e no Anexo 01 do RREO 6ºB.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 1', 'Verifica se o valor acumulado das receitas arrecadadas da MSC de dezembro é igual às receitas arrecadadas do Anexo 01 do RREO 6ºB. Na MSC de dezembro, é considerado o saldo final das contas começadas por 6212 e 6213 com detalhamento de natureza de receita.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00021', 'Contábil x Fiscal', 'E/DF', 'Igualdade nas receitas com tributos estaduais na MSC de dezembro e no Anexo 03 do RREO 6ºB.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 3', 'Verifica se o valor acumulado das receitas com tributos estaduais (ICMS, IPVA, ITCD, IRRF) da MSC de dezembro é igual ao informado no Anexo 03 do RREO 6ºB. Na MSC de dezembro, é considerado o saldo final das contas começadas por 6212 e 62132 e 62139 com detalhamento da naturezas de receitas.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00022', 'Contábil x Fiscal', 'M', 'Igualdade nas receitas com tributos municipais na MSC de dezembro e no Anexo 03 do RREO 6ºB.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 3', 'Verifica se o valor acumulado das receitas com tributos municipais ( IPTU, ISS, ITBI, IRRF ) da MSC de dezembro é igual ao informado no Anexo 03 do RREO 6ºB. Na MSC de dezembro, é considerado o saldo final das contas começadas por 6212 e 62132 e 62139 com detalhamento da naturezas de receitas.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00023', 'Contábil x Fiscal', 'E/DF', 'Igualdade nas receitas estaduais com transferências constitucionais na MSC de dezembro e no Anexo 03 do RREO 6ºB.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 3', 'Verifica se o valor acumulado das receitas estaduais com transferências ( Cota-Parte do FPE e Transferências do FUNDEB) da MSC de dezembro é igual ao informado no Anexo 03 do RREO 6ºB. Na MSC de dezembro, é considerado o saldo final das contas começadas por 6212 e 62132 e 62139 com detalhamento da naturezas de receitas.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00024', 'Contábil x Fiscal', 'M', 'Igualdade nas receitas municipais com transferências constitucionais na MSC de dezembro e no Anexo 03 do RREO 6ºB.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 3', 'Verifica se o valor acumulado das receitas municipais com transferências (Cotas-Partes do FPM, do ICMS, do IPVA, do ITR e Transferências do FUNDEB) da MSC de dezembro é igual ao informado no Anexo 03 do RREO 6ºB. Na MSC de dezembro, é considerado o saldo final das contas começadas por 6212 e 62132 e 62139 com detalhamento da naturezas de receitas.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00025', 'Contábil x Fiscal', 'E/DF/M', 'Igualdade das Despesas Orçamentárias empenhadas, liquidadas e pagas na MSC de dezembro e no RREO 6ºB.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 1', 'Verifica se o valor das despesas orçamentárias no Anexo 01 do RREO 6ºB está igual ao saldo final da MSC de dezembro das contas do grupo 62213 que tenham detalhamento de natureza de despesa. Avaliam-se valores empenhados, liquidados e pagos.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00026', 'Contábil x Fiscal', 'E/DF/M', 'Igualdade dos Restos a Pagar não processados no Anexo 01 do RREO 6ºB e na MSC de dezembro.', 'MSC RREO', 'MSCC - Dezembro RREO - ANEXO 1', 'Verifica se o valor dos RPNP no Anexo 01 do RREO 6ºB está igual ao saldo final das contas contábeis começadas por 6221305 e 6221306, com detalhamento de natureza de despesa, na MSC de dezembro.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00027', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de caixa e equivalente de caixas do Anexo 02 do RGF é menor ou igual ao saldo de caixa e equivalentes do Anexo 01 da DCA.', 'DCA RGF', 'DCA RGF - ANEXO 2', 'Compara o saldo da conta CEC da DCA com a disponibilidade de caixa bruta total do Anexo 2 do RGF. Disponibilidade de Caixa Bruta do Anexo 2 do RGF deve ser menor ou igual a 1.1.1.0.0.00.00 - Caixa e Equivalentes, do Anexo I-AB, da DCA.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00028', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de caixa e equivalente de caixas do Anexo 05 do RGF é menor ou igual ao saldo de caixa e equivalentes do Anexo 01 da DCA.', 'DCA RGF', 'DCA RGF - ANEXO 5', 'Compara o saldo da conta CEC da DCA com a disponibilidade de caixa bruta total do Anexo 5 do RGF. Disponibilidade de Caixa Bruta do Anexo 5 do RGF deve ser menor ou igual a 1.1.1.0.0.00.00 - Caixa e Equivalentes do Anexo I-AB, da DCA.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00029', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de despesas exceto-intra na função 09 (Prev. Social) é igual entre a MSC de Dezembro e o Anexo 02 do RREO.', 'MSC RREO', 'RREO - ANEXO 2 MSCC - Dezembro', 'Compara, entre RREO X  MSC de Dezembro, as Despesas Exceto Intraorçamentárias na função 09 (Previdência Social). Na MSC de Dezembro, utliza-se o saldo final para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 62213 com modalidade de aplicação diferente de 91 e classificação funcional igual a 09.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00030', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de despesas exceto-intra na função 10 (Saúde) é igual entre a MSC de Dezembro e o Anexo 02 do RREO.', 'MSC RREO', 'RREO - ANEXO 2 MSCC - Dezembro', 'Compara, entre RREO X  MSC de Dezembro, as Despesas Exceto Intraorçamentárias na função 10 (Saúde). Na MSC de Dezembro, utliza-se o saldo final para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 62213 com modalidade de aplicação diferente de 91 e classificação funcional igual a 10.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00031', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de despesas exceto-intra na função 12 (Educação) é igual entre a MSC de Dezembro e o Anexo 02 do RREO.', 'MSC RREO', 'RREO - ANEXO 2 MSCC - Dezembro', 'Compara, entre RREO X  MSC de Dezembro, as Despesas Exceto Intraorçamentárias na função 12 (Educação). Na MSC de Dezembro, utliza-se o saldo final para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 62213 com modalidade de aplicação diferente de 91 e classificação funcional igual a 12.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00032', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de despesas exceto-intra nas funções diferentes de 09, 10 e 12 é igual entre a MSC de Dezembro e o Anexo 02 do RREO.', 'MSC RREO', 'RREO - ANEXO 2 MSCC - Dezembro', 'Compara, entre RREO X  MSC de Dezembro, as Despesas Exceto Intraorçamentárias nas demais funções (Excetuando-se as funções de Saúde, Educação e Previdência Social). Na MSC de Dezembro, utliza-se o saldo final para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 62213 com modalidade de aplicação diferente de 91 e classificação funcional diferente de 09, 10 e 12.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00033', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de despesas intraorçamentárias com detalhamento de função/subfunção é igual entre a MSC de Dezembro e o Anexo 02 do RREO.', 'MSC RREO', 'RREO - ANEXO 2 MSCC - Dezembro', 'Compara as despesas por função entre RREO X  MSC de Dezembro - Intraorçamentárias. Na MSC de Dezembro, utliza-se o saldo final para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 62213 com modalidade de aplicação igual a 91.', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00034', 'Contábil x Fiscal', 'E/DF/M', 'Avalia a igualdade entre os saldos finais de RPP pagos e RPNP pagos na MSC de Dezembro e no Anexo 07 do RREO.', 'MSC RREO', 'RREO - ANEXO 7  MSCC - Dezembro', 'Compara o saldo final de RPPP e RPNPP executados no exercício entre o RREO - Anexo 07  x MSC de dezembro. Na MSC de encerramento, utliza-se o saldo final (ending_balance) para contas de classe 5 e 6. São avaliados os saldos das contas contábeis começadas por 6314 (RPNPP) e 6322 (RPPP).', FALSE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00035', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de caixa e equivalente de caixas do Anexo 05 do RGF é menor ou igual ao saldo de caixa e equivalentes da MSC de encerramento.', 'MSC RREO', 'RGF - ANEXO 5 MSCC - Dezembro', 'Compara o saldo da conta CEC da MSC de dezembro com a disponibilidade de caixa bruta total do Anexo 5 do RGF. Na MSC de dezembro, utliza-se o saldo final (ending_balance) para contas de classe 1 e 2. São avaliados os saldos das contas começadas por 111.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00036', 'Contábil x Fiscal', 'E/DF/M', 'Avalia se o valor de caixa e equivalente de caixas do Anexo 02 do RGF é menor ou igual ao saldo de caixa e equivalentes do Anexo 01 da MSC de encerramento.', 'MSC RREO', 'RGF - ANEXO 2 MSCC - Dezembro', 'Compara o saldo da conta CEC da MSC de dezembro com a disponibilidade de caixa bruta total do Anexo 2 do RGF. Na MSC de dezembro, utliza-se o saldo final (ending_balance) para contas de classe 1 e 2. São avaliados os saldos das contas começadas por 111.', FALSE);
