INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00042', 'Contábil x Fiscal', 'E/DF/M', 'Relação entre valores restituíveis na MSC e Obrigações Financeiras Extraorçamentárias no Anexo 05 do RGF. O valor do RGF deve ser maior ou igual ao valor apurado na MSC.', 'MSC  RGF', 'MSC - Dezembro RGF - Anexo 05', 'São avaliados na MSC de dezembro o saldo final das contas contábeis começadas com 2188 + começadas por 2288 + 218910105 + 218910108, sendo todas essas contas vinculadas ao Poder Executivo e associadas às fontes de recurso 860, 861, 862 e 869.', TRUE);
INSERT INTO siconfi_verificacoes (co_dimensao, no_verificacao, no_dimensao, no_aplicavel, no_desc, no_declaracao, no_anexo, no_finalidade, capag)
VALUES ('DIV', 'D4_00043', 'Contábil x Fiscal', 'E/DF/M', 'Igualdade entre os valores de Recursos Não Vinculados às Disponibilidades de Caixa e aos Restos a Pagar Processados e Não Processados de exercícios anteriores com os saldos finais da MSC de dezembro.', 'MSC  RGF', 'MSC - Dezembro RGF - Anexo 06', 'São avaliados na MSC de dezembro o saldo final das contas contábeis específicas de cada uma da colunas combinadas às fontes de recurso de cada uma das linhas (500 ou 501, 502 e 503). Contas por coluna: * Disponibilidade de caixa bruta: começadas por 11111,11121,11131,11133,11134,11135 * RP Liquidados e não pagos de exercicios anteriores: começadas por 6321,6313 * RP Liquidados e não pagos do exercício: começadas por 6327 * Restos a Pagar empenhados e não pagos de exercícios anteriores: começadas por 6311,6312', TRUE);
